  ('police-3fd24912-moex-00249', 'police-3fd24912', 'police-3fd24912-moex-111-15a7b19c', 'sub-police-3fd24912-01', NULL, 'single_choice', '依司法院大法官解釋，關於憲法保障之人格發展自由，下列敘述何者錯誤？', '["個人得經由締結契約，實現人格發展", "可藉由個人與他人生活資源之交換，實現人格發展", "兒童與少年的人格發展，較成年人更須保護", "收養行為係成立法定血親，無助於人格發展自由之實現"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:00+00:00", "source_pdf_sha1": "a526a29fb5cc", "answer_pdf_sha1": "53cf396c4907", "source_family": "moex-gov-tw", "moex": {"exam_code": "111070", "c": "504", "s": "0205", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "中華民國憲法與警察專業英文", "year": "111", "exam_name": "111年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、交通事業鐵路人員考試", "original_question_number": 29, "answer_corrected": false, "flags": [], "civil_slug": "police", "civil_category": "公共安全人員"}'::jsonb, NULL),
  ('police-3fd24912-moex-00250', 'police-3fd24912', 'police-3fd24912-moex-111-15a7b19c', 'sub-police-3fd24912-01', NULL, 'single_choice', '依司法院大法官解釋意旨，關於緊急命令，下列敘述何者錯誤？', '["具有暫時替代法律、變更法律效力之功能", "以不得再授權為補充規定即可逕予執行為原則", "例外有待執行機關以命令補充者，應於緊急命令中明文規定其意旨，於立法院完成追認程 序後，再行發布", "立法院就緊急命令行使追認權時，如認部分內容不當，得為部分變更"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:00+00:00", "source_pdf_sha1": "a526a29fb5cc", "answer_pdf_sha1": "53cf396c4907", "source_family": "moex-gov-tw", "moex": {"exam_code": "111070", "c": "504", "s": "0205", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "中華民國憲法與警察專業英文", "year": "111", "exam_name": "111年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、交通事業鐵路人員考試", "original_question_number": 30, "answer_corrected": false, "flags": [], "civil_slug": "police", "civil_category": "公共安全人員"}'::jsonb, NULL),
  ('police-3fd24912-moex-00251', 'police-3fd24912', 'police-3fd24912-moex-111-15a7b19c', 'sub-police-3fd24912-01', NULL, 'single_choice', '依憲法規定及司法院大法官解釋，關於行政院組織，下列敘述何者錯誤？', '["各機關之組織、編制及員額，應依立法者所制訂之準則性法律，基於政策或業務需要決定之", "立法者制定單獨組織法時，不得牴觸立法者所制訂之準則性法律", "國家機關之職權、設立程序及總員額，得以法律為準則性之規定", "立法院得以法律明定或授權以命令訂定行政院所屬各級機關之設置與組織"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:00+00:00", "source_pdf_sha1": "a526a29fb5cc", "answer_pdf_sha1": "53cf396c4907", "source_family": "moex-gov-tw", "moex": {"exam_code": "111070", "c": "504", "s": "0205", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "中華民國憲法與警察專業英文", "year": "111", "exam_name": "111年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、交通事業鐵路人員考試", "original_question_number": 31, "answer_corrected": false, "flags": [], "civil_slug": "police", "civil_category": "公共安全人員"}'::jsonb, NULL),
  ('police-3fd24912-moex-00252', 'police-3fd24912', 'police-3fd24912-moex-111-15a7b19c', 'sub-police-3fd24912-01', NULL, 'single_choice', '依據憲法增修條文對於「行政院對立法院負責」的規範設計，下列敘述何者正確？', '["行政院院長若有辭職或出缺之情事，在總統未任命行政院院長之前，應由立法院院長暫行 代理之責", "行政院認為立法院決議之條約案窒礙難行，得經總統核可於該決議案送達行政院10日內， 移請立法院覆議", "立法院得經全體立法委員3分之1以上連署，經總統核可後，對行政院院長提出不信任案", "立法院對於行政院之重要政策不贊同時，得以決議移請行政院變更之"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:00+00:00", "source_pdf_sha1": "a526a29fb5cc", "answer_pdf_sha1": "53cf396c4907", "source_family": "moex-gov-tw", "moex": {"exam_code": "111070", "c": "504", "s": "0205", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "中華民國憲法與警察專業英文", "year": "111", "exam_name": "111年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、交通事業鐵路人員考試", "original_question_number": 32, "answer_corrected": false, "flags": [], "civil_slug": "police", "civil_category": "公共安全人員"}'::jsonb, NULL),
  ('police-3fd24912-moex-00253', 'police-3fd24912', 'police-3fd24912-moex-111-15a7b19c', 'sub-police-3fd24912-01', NULL, 'single_choice', '下列何者非屬立法院之職權？', '["中央與地方權限爭議之解決權", "總統發布緊急命令之追認權", "總統宣布戒嚴之決議或追認權", "院際間爭議之調解權"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:00+00:00", "source_pdf_sha1": "a526a29fb5cc", "answer_pdf_sha1": "53cf396c4907", "source_family": "moex-gov-tw", "moex": {"exam_code": "111070", "c": "504", "s": "0205", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "中華民國憲法與警察專業英文", "year": "111", "exam_name": "111年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、交通事業鐵路人員考試", "original_question_number": 33, "answer_corrected": false, "flags": [], "civil_slug": "police", "civil_category": "公共安全人員"}'::jsonb, NULL),
