  ('police-3fd24912-moex-00255', 'police-3fd24912', 'police-3fd24912-moex-111-15a7b19c', 'sub-police-3fd24912-01', NULL, 'single_choice', '關於司法院大法官，下列敘述何者錯誤？', '["並為院長、副院長之大法官，不受任期之保障", "司法院大法官組成憲法法庭，依法審理法規範憲法審查及裁判憲法審查、機關爭議、法官 懲戒等案件", "曾實際執行律師業務25年以上而聲譽卓著者，具備大法官資格", "司法院院長、副院長同時出缺時，由總統就大法官中指定1人代理院長"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:00+00:00", "source_pdf_sha1": "a526a29fb5cc", "answer_pdf_sha1": "53cf396c4907", "source_family": "moex-gov-tw", "moex": {"exam_code": "111070", "c": "504", "s": "0205", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "中華民國憲法與警察專業英文", "year": "111", "exam_name": "111年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、交通事業鐵路人員考試", "original_question_number": 35, "answer_corrected": false, "flags": [], "civil_slug": "police", "civil_category": "公共安全人員"}'::jsonb, NULL),
  ('police-3fd24912-moex-00256', 'police-3fd24912', 'police-3fd24912-moex-111-15a7b19c', 'sub-police-3fd24912-01', NULL, 'single_choice', '有關我國釋憲制度，下列敘述何者錯誤？', '["法律違憲之審查採集中制", "兼有具體審查與抽象審查", "命令違憲之審查為分散制", "統一法令解釋亦屬違憲審查"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:00+00:00", "source_pdf_sha1": "a526a29fb5cc", "answer_pdf_sha1": "53cf396c4907", "source_family": "moex-gov-tw", "moex": {"exam_code": "111070", "c": "504", "s": "0205", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "中華民國憲法與警察專業英文", "year": "111", "exam_name": "111年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、交通事業鐵路人員考試", "original_question_number": 36, "answer_corrected": false, "flags": [], "civil_slug": "police", "civil_category": "公共安全人員"}'::jsonb, NULL),
  ('police-3fd24912-moex-00257', 'police-3fd24912', 'police-3fd24912-moex-111-15a7b19c', 'sub-police-3fd24912-01', NULL, 'single_choice', '依憲法訴訟法之規定，下列何者屬於「機關爭議案件」？', '["臺北市認為其憲法上的地方自治權限為中央所侵害", "考試院認為其關於考試行政的權限為行政院所侵害", "行政院認為立法院所制定某個法律中的條文，致使其行政權被侵害", "臺北市認為其地方制度法所保障的自治權限為新北市所侵害"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:00+00:00", "source_pdf_sha1": "a526a29fb5cc", "answer_pdf_sha1": "53cf396c4907", "source_family": "moex-gov-tw", "moex": {"exam_code": "111070", "c": "504", "s": "0205", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "中華民國憲法與警察專業英文", "year": "111", "exam_name": "111年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、交通事業鐵路人員考試", "original_question_number": 37, "answer_corrected": false, "flags": [], "civil_slug": "police", "civil_category": "公共安全人員"}'::jsonb, NULL),
  ('police-3fd24912-moex-00258', 'police-3fd24912', 'police-3fd24912-moex-111-15a7b19c', 'sub-police-3fd24912-01', NULL, 'single_choice', '依司法院大法官解釋，有關地方自治，下列敘述何者錯誤？', '["地方自治團體行政機關人員受立法院各種委員會邀請到會備詢時，有到會備詢之義務", "地方自治團體在憲法及法律保障之範圍內，享有自主及獨立之地位", "使地方人民對於地方事務及公共政策有直接參與或形成之權，在於實現住民自治之理念", "立法院不得以地方自治團體所屬公務員之未到會備詢為理由，而刪減或擱置中央機關依法 對地方自治團體補助款預算"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:00+00:00", "source_pdf_sha1": "a526a29fb5cc", "answer_pdf_sha1": "53cf396c4907", "source_family": "moex-gov-tw", "moex": {"exam_code": "111070", "c": "504", "s": "0205", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "中華民國憲法與警察專業英文", "year": "111", "exam_name": "111年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、交通事業鐵路人員考試", "original_question_number": 38, "answer_corrected": false, "flags": [], "civil_slug": "police", "civil_category": "公共安全人員"}'::jsonb, NULL)
